settings.custom_liquid:
{% assign all_out_of_stock = true %}
{% assign stock_is_one = false %}
{% assign brand_handle = product.vendor | downcase %}

{% if brand_handle == "amio" %}
  {% for variant in product.variants %}
    {% if variant.inventory_quantity > 0 %}
      {% assign all_out_of_stock = false %}
    {% endif %}
    {% if variant.inventory_quantity == 1 %}
      {% assign stock_is_one = true %}
    {% endif %}
  {% endfor %}

  {% if stock_is_one %}
    <div style="font-weight: bold; border: 2px solid #FC7D00; border-radius: 5px; background-color: #ffffff; padding: 10px;">
      <span style="color: red;">Nog maar 1 op voorraad</span>. Bestel je er 2 of meer? dan is de levertijd 5-7 werkdagen.
    </div>
  {% elsif all_out_of_stock %}
    <div style="font-weight: bold; border: 2px solid #FC7D00; border-radius: 5px; background-color: #ffffff; padding: 10px;">
      <span style="color: red;">Backorder - Niet voorradig</span>, wel te bestellen. Geschatte levering: 5-7 werkdagen.
    </div>
  {% endif %}
{% endif %}
